record.field:
# Get the model from context or active model
model_name = context.get('active_model')
if model_name:
    action = env['easy.mode.toggler'].toggle_easy_mode(model_name)
else:
    raise UserError('No model context found for Easy Mode toggle')

model_name = context.get('params', {}).get('model')
if not model_name:
    model_name = context.get('active_model')

if model_name:
    toggler = env['easy.mode.toggler']
    if toggler.is_easy_mode_available(model_name):
        result = toggler.toggle_easy_mode(model_name)
        # Reload current page
        action = {
            'type': 'ir.actions.client',
            'tag': 'reload'
        }
    else:
        action = {
            'type': 'ir.actions.client',
            'tag': 'display_notification',
            'params': {
                'title': 'Easy Mode',
                'message': 'Easy Mode not available for this model',
                'type': 'warning'
            }
        }
else:
    action = {
        'type': 'ir.actions.client',
        'tag': 'display_notification',
        'params': {
            'title': 'Error',
            'message': 'No model context found',
            'type': 'danger'
        }
    }
